import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Star, TrendingUp, Zap, Heart, Code, Gamepad2, Filter, Info, ArrowRight, Search } from 'lucide-react';
import { LayoutWithStats } from '../types';

type PreferenceType = 'comfort' | 'speed' | 'gaming' | 'programming' | 'pinky_strain';

interface Preference {
  id: PreferenceType;
  name: string;
  description: string;
  icon: React.ReactNode;
  color: string;
}

interface RecommendationError {
  message: string;
  details?: string;
}

const RecommendationsPage: React.FC = () => {
  const [selectedPreference, setSelectedPreference] = useState<PreferenceType>('comfort');
  const [recommendations, setRecommendations] = useState<LayoutWithStats[]>([]);
  const [loading, setLoading] = useState(false);
  const [allLayouts, setAllLayouts] = useState<LayoutWithStats[]>([]);
  const [error, setError] = useState<RecommendationError | null>(null);

  const preferences: Preference[] = [
    {
      id: 'comfort',
      name: 'Comfort',
      description: 'Minimize finger strain and maximize typing comfort',
      icon: <Heart className="w-6 h-6" />,
      color: 'from-pink-500 to-rose-500'
    },
    {
      id: 'speed',
      name: 'Speed',
      description: 'Optimize for maximum typing speed and flow',
      icon: <Zap className="w-6 h-6" />,
      color: 'from-yellow-500 to-orange-500'
    },
    {
      id: 'gaming',
      name: 'Gaming',
      description: 'Best layouts for gaming performance',
      icon: <Gamepad2 className="w-6 h-6" />,
      color: 'from-blue-500 to-indigo-500'
    },
    {
      id: 'programming',
      name: 'Programming',
      description: 'Optimized for coding and special characters',
      icon: <Code className="w-6 h-6" />,
      color: 'from-green-500 to-emerald-500'
    },
    {
      id: 'pinky_strain',
      name: 'Pinky Relief',
      description: 'Minimize pinky finger usage and strain',
      icon: <TrendingUp className="w-6 h-6" />,
      color: 'from-purple-500 to-violet-500'
    }
  ];

  useEffect(() => {
    fetchAllLayouts();
  }, []);

  useEffect(() => {
    if (allLayouts.length > 0) {
      generateRecommendations();
    }
  }, [selectedPreference, allLayouts]);

  const fetchAllLayouts = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('/api/layouts');
      if (response.ok) {
        const data = await response.json();
        setAllLayouts(data);
      } else {
        const errorMessage = response.status === 404 
          ? 'Layout data not found. Please ensure the backend is running.'
          : `Failed to fetch layouts (${response.status})`;
        setError({ 
          message: errorMessage,
          details: 'Unable to load keyboard layout data from the server.'
        });
      }
    } catch (error) {
      console.error('Error fetching layouts:', error);
      setError({ 
        message: 'Unable to connect to the server',
        details: 'Please check your internet connection and try again.'
      });
    } finally {
      setLoading(false);
    }
  };

  const generateRecommendations = async () => {
    if (allLayouts.length === 0) return;
    
    setLoading(true);
    setError(null);
    
    try {
      // Try to get recommendations from API first
      const response = await fetch('/api/recommendations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ preferences: selectedPreference }),
      });
      
      if (response.ok) {
        const data = await response.json();
        setRecommendations(data);
        return;
      }
    } catch (error) {
      console.log('API recommendations not available, using client-side scoring:', error);
    }
    
    // Fallback to client-side scoring if API is not available
    try {
      const scored = scoreLayouts(allLayouts, selectedPreference);
      setRecommendations(scored.slice(0, 8)); // Show top 8 recommendations
    } catch (error) {
      console.error('Error generating recommendations:', error);
      setError({ 
        message: 'Failed to generate recommendations',
        details: 'Unable to analyze layout data. Please try again.'
      });
    } finally {
      setLoading(false);
    }
  };

  const scoreLayouts = (layouts: LayoutWithStats[], preference: PreferenceType): LayoutWithStats[] => {
    const weights = {
      comfort: {
        effort: -0.25,
        distance: -0.2,
        pinky_distance: -0.15,
        pinky_off_home_pct: -0.1,
        same_finger_bigrams_pct: -0.15,
        lateral_stretch_pct: -0.15
      },
      speed: {
        roll_in_pct: 0.3,
        roll_out_pct: 0.2,
        trigram_alt_pct: 0.25,
        same_finger_bigrams_pct: -0.25
      },
      gaming: {
        effort: -0.2,
        distance: -0.15,
        col5_6_pct: -0.2,
        roll_in_pct: 0.2,
        two_row_jumps_pct: -0.15,
        pinky_scissors_pct: -0.1
      },
      programming: {
        lateral_stretch_pct: -0.2,
        skip_bigrams_pct: -0.15,
        effort: -0.2,
        same_finger_bigrams_pct: -0.15,
        trigram_alt_pct: 0.15,
        roll_in_pct: 0.15
      },
      pinky_strain: {
        pinky_distance: -0.3,
        pinky_off_home_pct: -0.25,
        pinky_scissors_pct: -0.2,
        col5_6_pct: -0.25
      }
    };

    const selectedWeights = weights[preference];

    return layouts.map(layout => {
      let score = 0;
      
      for (const [metric, weight] of Object.entries(selectedWeights)) {
        const value = (layout as any)[metric];
        if (value !== null && value !== undefined) {
          let normalizedValue = value;
          if (metric.endsWith('_pct')) {
            normalizedValue = value / 100;
          }
          score += normalizedValue * weight;
        }
      }
      
      return {
        ...layout,
        recommendation_score: score
      };
    }).sort((a, b) => (b.recommendation_score || 0) - (a.recommendation_score || 0));
  };

  const getMetricColor = (value: number | undefined, good: number, bad: number, lowerIsBetter: boolean = true) => {
    if (value === undefined) return 'text-gray-400';
    if (lowerIsBetter) {
      return value <= good ? 'text-green-500' : value >= bad ? 'text-red-500' : 'text-yellow-500';
    } else {
      return value >= good ? 'text-green-500' : value <= bad ? 'text-red-500' : 'text-yellow-500';
    }
  };


  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
      <div className="max-w-7xl mx-auto px-4">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold bg-gradient-to-r from-purple-600 to-blue-600 bg-clip-text text-transparent mb-4">
            Layout Recommendations
          </h1>
          <p className="text-gray-600 dark:text-gray-300 max-w-2xl mx-auto">
            Get personalized keyboard layout recommendations based on your typing preferences and use case.
          </p>
        </div>

        {/* Preference Selection */}
        <div className="bg-white dark:bg-gray-800 rounded-xl p-6 mb-8 shadow-lg">
          <div className="flex items-center gap-2 mb-4">
            <Filter className="text-purple-600" size={24} />
            <h2 className="text-xl font-semibold">Choose Your Priority</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
            {preferences.map((pref) => (
              <button
                key={pref.id}
                onClick={() => setSelectedPreference(pref.id)}
                className={`p-4 rounded-lg border-2 transition-all ${
                  selectedPreference === pref.id
                    ? 'border-purple-500 bg-purple-50 dark:bg-purple-900/20'
                    : 'border-gray-200 dark:border-gray-700 hover:border-purple-300'
                }`}
              >
                <div className={`w-12 h-12 rounded-lg bg-gradient-to-r ${pref.color} flex items-center justify-center text-white mb-3 mx-auto`}>
                  {pref.icon}
                </div>
                <h3 className="font-semibold mb-1">{pref.name}</h3>
                <p className="text-xs text-gray-600 dark:text-gray-400">{pref.description}</p>
              </button>
            ))}
          </div>
        </div>

        {/* Recommendations */}
        {loading ? (
          <div className="flex items-center justify-center py-12">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600"></div>
          </div>
        ) : (
          <div>
            <div className="flex items-center gap-2 mb-6">
              <Star className="text-yellow-500" size={24} />
              <h2 className="text-2xl font-bold">Recommended for {preferences.find(p => p.id === selectedPreference)?.name}</h2>
            </div>
            
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {recommendations.map((layout, index) => (
                <Link
                  key={layout.id}
                  to={`/layouts/${layout.slug}`}
                  className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg hover:shadow-xl transition-all hover:scale-[1.02] border-2 hover:border-purple-300 dark:hover:border-purple-700"
                >
                  <div className="flex items-start justify-between mb-4">
                    <div>
                      <div className="flex items-center gap-2 mb-2">
                        <span className="bg-purple-100 dark:bg-purple-900 text-purple-600 dark:text-purple-400 text-sm font-bold px-2 py-1 rounded">
                          #{index + 1}
                        </span>
                        <h3 className="text-xl font-bold">{layout.name}</h3>
                      </div>
                      <p className="text-gray-600 dark:text-gray-400 text-sm">{layout.description}</p>
                      <span className="inline-block bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 text-xs px-2 py-1 rounded mt-2">
                        {layout.type}
                      </span>
                    </div>
                    {layout.recommendation_score && (
                      <div className="text-right">
                        <div className="text-2xl font-bold text-purple-600">
                          {Math.round((layout.recommendation_score + 1) * 50)}
                        </div>
                        <div className="text-xs text-gray-500">Match Score</div>
                      </div>
                    )}
                  </div>

                  {/* Key Metrics */}
                  <div className="grid grid-cols-4 gap-4 text-sm">
                    <div className="text-center">
                      <div className="text-xs text-gray-500 mb-1">Effort</div>
                      <div className={`font-semibold ${getMetricColor(layout.effort, 1.2, 1.4)}`}>
                        {layout.effort?.toFixed(2) || 'N/A'}
                      </div>
                    </div>
                    <div className="text-center">
                      <div className="text-xs text-gray-500 mb-1">SFBs</div>
                      <div className={`font-semibold ${getMetricColor(layout.same_finger_bigrams_pct, 2, 5)}`}>
                        {layout.same_finger_bigrams_pct?.toFixed(1)}%
                      </div>
                    </div>
                    <div className="text-center">
                      <div className="text-xs text-gray-500 mb-1">Roll In</div>
                      <div className={`font-semibold ${getMetricColor(layout.roll_in_pct, 15, 8, false)}`}>
                        {layout.roll_in_pct?.toFixed(1)}%
                      </div>
                    </div>
                    <div className="text-center">
                      <div className="text-xs text-gray-500 mb-1">Alt</div>
                      <div className={`font-semibold ${getMetricColor(layout.trigram_alt_pct, 25, 15, false)}`}>
                        {layout.trigram_alt_pct?.toFixed(1)}%
                      </div>
                    </div>
                  </div>

                  {/* Why Recommended */}
                  <div className="mt-4 p-3 bg-purple-50 dark:bg-purple-900/20 rounded-lg">
                    <div className="flex items-center gap-1 mb-1">
                      <Info size={14} className="text-purple-600" />
                      <span className="text-xs font-semibold text-purple-600">Why recommended:</span>
                    </div>
                    <p className="text-xs text-gray-600 dark:text-gray-400">
                      {getRecommendationReason(layout, selectedPreference)}
                    </p>
                  </div>
                </Link>
              ))}
            </div>
            
            {recommendations.length === 0 && !loading && (
              <div className="text-center py-12">
                <p className="text-gray-500 dark:text-gray-400 text-lg">
                  No recommendations available. Try a different preference or add more layouts.
                </p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );

  function getRecommendationReason(layout: LayoutWithStats, preference: PreferenceType): string {
    switch (preference) {
      case 'comfort':
        return `Low effort (${layout.effort?.toFixed(2)}) and minimal same-finger bigrams (${layout.same_finger_bigrams_pct?.toFixed(1)}%) for comfortable typing.`;
      case 'speed':
        return `High roll percentage (${((layout.roll_in_pct || 0) + (layout.roll_out_pct || 0)).toFixed(1)}%) and strong alternation (${layout.trigram_alt_pct?.toFixed(1)}%) for fast typing.`;
      case 'gaming':
        return `Optimized key placement for gaming with low effort (${layout.effort?.toFixed(2)}) and good accessibility.`;
      case 'programming':
        return `Low lateral stretches (${layout.lateral_stretch_pct?.toFixed(1)}%) and balanced metrics for coding comfort.`;
      case 'pinky_strain':
        return `Minimized pinky usage (${layout.pinky_off_home_pct?.toFixed(1)}% off-home) and reduced pinky strain.`;
      default:
        return 'Well-balanced layout suitable for general use.';
    }
  }
};

export default RecommendationsPage;
